#!/usr/bin/env python3
"""
LanceDB native (non-Tantivy) full-text search prototype.

Creates an `articles` table, builds a Lance-native FTS index on the `body`
column, runs two BM25 queries, and writes combined results to JSON.
"""

import json
import os
import shutil

import lancedb
import numpy as np
import pyarrow as pa

# ── Configuration ──────────────────────────────────────────────────────────
LANCEDB_URI = os.environ.get("LANCEDB_URI", "/workspace/db")
FTS_QUERY_1 = os.environ.get("FTS_QUERY_1", "REDACTED")
FTS_QUERY_2 = os.environ.get("FTS_QUERY_2", "REDACTED")
OUTPUT_DIR = "/workspace/output"
OUTPUT_FILE = os.path.join(OUTPUT_DIR, "fts_results.json")

# ── Article corpus ─────────────────────────────────────────────────────────
# Each article body is distinct so that the two FTS queries resolve to a
# single unambiguous top result.

ARTICLES = [
    {
        "id": 1,
        "title": "Introduction to Vector Databases",
        "body": "A REDACTED is designed to store and query high-dimensional vector embeddings efficiently. Unlike traditional relational databases that rely on exact matches, a REDACTED uses approximate nearest neighbor search to find semantically similar items. This makes REDACTEDs essential for modern AI applications such as retrieval-augmented generation, recommendation systems, and semantic search. Popular REDACTED implementations include Pinecone, Weaviate, Milvus, and Qdrant, each offering different trade-offs between latency, accuracy, and scalability.",
    },
    {
        "id": 2,
        "title": "The Lance Columnar Format",
        "body": "Lance is a modern columnar data format optimized for machine learning workloads. The Lance format extends the ideas behind Apache Parquet and Apache Arrow by adding native support for variable-length nested types, vector columns, and fast random access. Data stored in the Lance format can be read incrementally without loading entire files, which is critical for training and inference pipelines. The format also supports efficient versioning and append-only writes, making it suitable for continuously evolving datasets.",
    },
    {
        "id": 3,
        "title": "BM25 Ranking Explained",
        "body": "BM25 is a probabilistic ranking function used by search engines to estimate the relevance of documents to a given search query. It builds on the term frequency–inverse document frequency model by incorporating document length normalization. BM25 assigns higher scores to documents that contain query terms more frequently, but dampens the effect of very high term frequencies and penalizes very long documents. Most full-text search engines, including Elasticsearch and LanceDB, use BM25 as their default scoring algorithm.",
    },
    {
        "id": 4,
        "title": "Columnar Storage Benefits",
        "body": "Columnar storage formats like Parquet and Lance organize data by columns rather than by rows. This layout allows analytical queries to read only the columns they need, dramatically reducing I/O. Columnar formats also enable efficient compression because values within a column tend to share similar data characteristics. For data scientists and engineers, columnar storage translates to faster queries, lower storage costs, and better interoperability between tools in the modern data stack.",
    },
    {
        "id": 5,
        "title": "Embedding Models Overview",
        "body": "Embedding models transform text, images, or other data types into dense vector representations. These embeddings capture semantic meaning, enabling similarity search across large corpora. Popular embedding models include OpenAI text-embedding-ada-002, Cohere embeddings, and open-source alternatives like SentenceTransformers. Once embeddings are generated, they are typically stored in a REDACTED for fast retrieval during inference or search operations.",
    },
    {
        "id": 6,
        "title": "Apache Arrow and Zero-Copy Reads",
        "body": "Apache Arrow defines an in-memory columnar format that enables zero-copy reads between different data processing systems. By standardizing the layout of tabular data in memory, Arrow eliminates the need for serialization and deserialization when exchanging data between libraries. Arrow is the foundation upon which many modern data tools are built, including Pandas, Spark, and LanceDB. The Arrow format ensures that data can be passed between processes with minimal overhead.",
    },
    {
        "id": 7,
        "title": "Approximate Nearest Neighbor Search",
        "body": "Approximate nearest neighbor (ANN) search is a technique used to quickly find items in a high-dimensional space that are close to a given query point. Unlike exact search, ANN trades a small amount of accuracy for dramatic speed improvements. Common ANN algorithms include HNSW, IVF-PQ, and Annoy. In a REDACTED, ANN indexes are built on embedding columns to enable sub-millisecond similarity queries over millions of vectors.",
    },
    {
        "id": 8,
        "title": "Data Versioning with LanceDB",
        "body": "LanceDB provides built-in data versioning that allows users to track changes to their datasets over time. Every write operation creates a new version, and previous versions remain accessible without duplication. This is particularly useful in machine learning workflows where data lineage and reproducibility are critical. Users can roll back to any prior version, compare diffs between versions, and branch datasets for experimentation.",
    },
    {
        "id": 9,
        "title": "Full-Text Search in Modern Databases",
        "body": "Full-text search enables users to query unstructured text data using natural language terms. Modern databases integrate full-text search alongside vector search, allowing hybrid queries that combine keyword relevance with semantic similarity. LanceDB supports both Tantivy-based and native Lance-based full-text search indexes. The native implementation avoids an external dependency and stores the inverted index directly in the Lance format, simplifying deployment and reducing overhead.",
    },
    {
        "id": 10,
        "title": "Inverted Index Internals",
        "body": "An inverted index maps each term in a corpus to the list of documents that contain it. This data structure is the backbone of full-text search engines and enables sub-linear query times. When a search query is issued, the engine looks up each query term in the inverted index, retrieves the matching document IDs, and ranks the results using a scoring function such as BM25. Building an inverted index involves tokenization, stop-word removal, stemming, and optional positional encoding for phrase queries.",
    },
    {
        "id": 11,
        "title": "Vector Index Types Compared",
        "body": "There are several types of vector indexes, each suited to different use cases. IVF (inverted file) indexes partition the vector space into clusters and only search relevant clusters at query time. HNSW (hierarchical navigable small world) graphs offer high recall with fast query times but require more memory. Product quantization (PQ) compresses vectors to reduce memory usage at the cost of some accuracy. LanceDB supports all of these index types and allows users to create multi-index hybrid search pipelines.",
    },
    {
        "id": 12,
        "title": "Parquet vs Lance Format",
        "body": "While Parquet has been the dominant columnar format for analytical workloads, the Lance format addresses several limitations that Parquet faces in ML contexts. Lance supports fast random access via an enhanced index structure, native vector column types, and efficient append operations without rewriting entire files. Parquet requires reading row groups sequentially, whereas Lance can read individual rows in O(1) time. For machine learning data pipelines, the Lance format offers significant performance improvements over traditional columnar formats.",
    },
    {
        "id": 13,
        "title": "Hybrid Search Strategies",
        "body": "Hybrid search combines keyword-based full-text search with semantic vector search to deliver more relevant results than either method alone. In a hybrid pipeline, BM25 scores from full-text search and cosine similarity scores from vector search are fused using techniques like reciprocal rank fusion. LanceDB makes it easy to run hybrid queries by maintaining both vector indexes and full-text search indexes on the same table, allowing users to retrieve results that match both the query keywords and the query intent.",
    },
    {
        "id": 14,
        "title": "Tokenization and Text Preprocessing",
        "body": "Tokenization is the process of splitting text into individual terms or tokens that can be indexed and searched. Common preprocessing steps include lowercasing, stop-word removal, stemming, and ASCII folding. The choice of tokenizer significantly affects search quality and index size. LanceDB native full-text search supports configurable tokenization options including simple, whitespace, and n-gram tokenizers, as well as language-specific stemming for over a dozen languages.",
    },
    {
        "id": 15,
        "title": "Scalable Vector Search at Production",
        "body": "Deploying a REDACTED in production requires careful attention to scalability, latency, and consistency. Sharding distributes vectors across multiple nodes, while replication ensures fault tolerance. Caching frequently accessed embeddings and pre-filtering by metadata can dramatically reduce query latency. LanceDB is designed to scale from single-node development setups to distributed production deployments, with consistent APIs across both configurations.",
    },
    {
        "id": 16,
        "title": "The Role of Metadata Filtering",
        "body": "Metadata filtering allows users to narrow down search results by applying boolean predicates on non-vector columns. For example, in an e-commerce search system, users might filter by price range, category, or brand before performing a vector similarity search. LanceDB supports rich metadata filtering expressions that can be combined with both vector search and full-text search queries, enabling precise and efficient retrieval from large datasets.",
    },
    {
        "id": 17,
        "title": "Understanding Reciprocal Rank Fusion",
        "body": "Reciprocal rank fusion (RRF) is a technique for merging ranked lists from multiple search methods into a single unified ranking. Each document receives a score inversely proportional to its rank position in each list, and the scores are summed across all lists. RRF is particularly useful in hybrid search pipelines where BM25 and vector search produce different rankings. LanceDB supports RRF as a built-in fusion strategy for combining full-text and vector search results.",
    },
    {
        "id": 18,
        "title": "LanceDB Architecture Overview",
        "body": "LanceDB is a serverless REDACTED built on the Lance columnar format. It stores data locally or in cloud object storage and provides both Python and JavaScript SDKs. The architecture separates compute from storage, allowing multiple processes to read the same dataset concurrently. LanceDB supports vector search, full-text search, and hybrid search out of the box, with no external dependencies required for the native full-text search implementation.",
    },
    {
        "id": 19,
        "title": "Real-Time Search with Streaming Data",
        "body": "Many applications require real-time search over continuously arriving data streams. LanceDB supports incremental index updates, allowing new documents to be indexed without rebuilding the entire index. This is critical for use cases like log analysis, social media monitoring, and news search, where freshness matters. The native Lance-based full-text search index supports append-only writes, making it well-suited for streaming ingestion workloads.",
    },
    {
        "id": 20,
        "title": "Choosing the Right Distance Metric",
        "body": "When performing vector search, the choice of distance metric affects which results are considered similar. Common metrics include cosine distance, Euclidean distance (L2), and inner product (dot product). Cosine distance is normalized and focuses on direction, making it popular for text embeddings. L2 distance captures both direction and magnitude. LanceDB lets users specify the distance metric when creating a vector index, defaulting to L2 for most use cases.",
    },
    {
        "id": 21,
        "title": "Data Ingestion Pipelines for Search",
        "body": "Building an effective search system requires a robust data ingestion pipeline that cleans, transforms, and indexes raw data. Typical steps include extracting text from documents, generating embeddings, enriching metadata, and writing to a REDACTED. LanceDB integrates smoothly with popular data frameworks like Apache Spark, Dask, and Ray, enabling batch and streaming ingestion at scale. Proper pipeline design ensures that search indexes remain fresh and consistent.",
    },
    {
        "id": 22,
        "title": "Lance Format Specification Details",
        "body": "The Lance format specification defines how columnar data is laid out on disk, including metadata pages, dictionary encoding, and vector-specific structures. Each Lance file is composed of metadata at the tail, enabling fast schema discovery. The format supports transactions via manifest files, allowing atomic commits of new data versions. Compared to other columnar formats, the Lance format is uniquely optimized for both analytical scans and point lookups, bridging the gap between OLAP and ML workloads.",
    },
    {
        "id": 23,
        "title": "Semantic Search Beyond Keywords",
        "body": "Semantic search goes beyond keyword matching by understanding the intent and contextual meaning behind a query. Using dense vector embeddings, semantic search can retrieve documents that are conceptually related even when they do not share exact terms. For example, a query about climate change might return documents mentioning global warming, carbon emissions, or greenhouse gases. Combining semantic search with traditional full-text search in a REDACTED yields the best of both worlds.",
    },
    {
        "id": 24,
        "title": "Managing Large-Scale Vector Indexes",
        "body": "As vector datasets grow to billions of embeddings, managing index size and query latency becomes challenging. Techniques like product quantization compress vectors from 128+ dimensions to compact codes, reducing memory usage by orders of magnitude. Distributed REDACTEDs shard indexes across machines and use distributed consensus protocols to maintain consistency. LanceDB leverages the Lance format to store indexes alongside data, avoiding the need for separate index management systems.",
    },
    {
        "id": 25,
        "title": "Full-Text Search Performance Tuning",
        "body": "Optimizing full-text search performance involves tuning tokenization, indexing, and ranking parameters. Removing stop words reduces index size, while stemming improves recall by matching word variants. BM25 parameters k1 and b control term frequency saturation and document length normalization respectively. LanceDB native full-text search exposes these parameters, allowing users to fine-tune search quality for their specific corpus and query patterns.",
    },
]


def main():
    rng = np.random.default_rng(1)

    # ── Remove any existing database for a clean slate ────────────────────
    if os.path.exists(LANCEDB_URI):
        shutil.rmtree(LANCEDB_URI)

    # ── Connect to LanceDB ───────────────────────────────────────────────
    db = lancedb.connect(LANCEDB_URI)

    # ── Build the table with pyarrow ──────────────────────────────────────
    ids = pa.array([a["id"] for a in ARTICLES], type=pa.int64())
    titles = pa.array([a["title"] for a in ARTICLES], type=pa.string())
    bodies = pa.array([a["body"] for a in ARTICLES], type=pa.string())
    vectors = pa.array(
        [rng.random(4).astype(np.float32).tolist() for _ in ARTICLES],
        type=pa.list_(pa.float32(), 4),
    )

    schema = pa.schema(
        [
            pa.field("id", pa.int64()),
            pa.field("title", pa.string()),
            pa.field("body", pa.string()),
            pa.field("vector", pa.list_(pa.float32(), 4)),
        ]
    )

    table_data = pa.table(
        {"id": ids, "title": titles, "body": bodies, "vector": vectors},
        schema=schema,
    )

    table = db.create_table("articles", table_data, mode="overwrite")
    print(f"Created table 'articles' with {len(table)} rows")

    # ── Build native (Lance-based) FTS index on body ──────────────────────
    table.create_fts_index("body", use_tantivy=False, replace=True)
    print("Created native FTS index on 'body' column")

    # Verify the index exists
    indices = table.list_indices()
    print(f"Indices: {indices}")

    # ── Run FTS queries ───────────────────────────────────────────────────
    results_q1 = table.search(FTS_QUERY_1, query_type="fts").limit(3).to_list()
    results_q2 = table.search(FTS_QUERY_2, query_type="fts").limit(3).to_list()

    print(f"\nQuery 1 ('{FTS_QUERY_1}') top result: id={results_q1[0]['id']}, "
          f"title='{results_q1[0]['title']}', score={results_q1[0]['_score']}")
    print(f"Query 2 ('{FTS_QUERY_2}') top result: id={results_q2[0]['id']}, "
          f"title='{results_q2[0]['title']}', score={results_q2[0]['_score']}")

    # ── Write output ──────────────────────────────────────────────────────
    os.makedirs(OUTPUT_DIR, exist_ok=True)

    output = {
        "query_1": results_q1,
        "query_2": results_q2,
    }

    with open(OUTPUT_FILE, "w") as f:
        json.dump(output, f, indent=2, default=str)

    print(f"\nResults written to {OUTPUT_FILE}")


if __name__ == "__main__":
    main()
